import sailpoint.tools.Util;

  import sailpoint.api.IdentityService;

  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.Application;
  import sailpoint.object.QueryOptions;

  boolean triggerJoiner = false ;

  String ATTR_NAME_AUTH_SOURCE_APP_NAME	="authSourceAppName" ;

  if(identity!=null){

    String ministry = identity.getStringAttribute("ministry");
    String type = identity.getStringAttribute("type");

    if(!Util.nullSafeCaseInsensitiveEq("AMITA Health",ministry)){
      if(Util.nullSafeCaseInsensitiveEq("non-hr contractor",type)){
        triggerJoiner = true;
      } 
    } else if (Util.nullSafeCaseInsensitiveEq("AMITA Health",ministry)){
          
      if(Util.nullSafeCaseInsensitiveEq("non-hr contractor",type)){
        triggerJoiner = true;
      } else{
        String identityAuthSourceAppName = identity.getStringAttribute(ATTR_NAME_AUTH_SOURCE_APP_NAME) ;

        if(Util.isNotNullOrEmpty(identityAuthSourceAppName)){

          Application authSourceApplication = context.getObjectByName(Application.class, identityAuthSourceAppName);

          if(authSourceApplication!=null){

            IdentityService idService = new IdentityService(context);

            List authSourceAppLinks = idService.getLinks(identity,authSourceApplication);

            if(authSourceAppLinks!=null && !authSourceAppLinks.isEmpty()){

              for(Link authSourceAppLink: authSourceAppLinks){

                if(!authSourceAppLink.isDisabled()){

                  triggerJoiner = true ;
                  break;
                }
              }

            }
          }

        }      
      }

    }
  }

return triggerJoiner ;
